import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Container, Flex, Section, Heading } from "@radix-ui/themes";
import './App.css';
import { useState } from "react";
import { useMouseMove, useValue } from "react-ui-animate";
import Navigation from "./Navigation";
import About from "./About";


function App() {

  const [cursorState, setCursorState] = useState({
    xPercent: 0,
    yPercent: 0
  });

  const windowWidth = window.innerWidth;
  const windowHeight = window.innerHeight;

  const x = useValue(0);
  const y = useValue(0);

  useMouseMove(({ mouseX, mouseY }) => {
    x.value = mouseX;
    y.value = mouseY;
    let xPercent = x.value.value / windowWidth;
    let yPercent = y.value.value / windowHeight;
    xPercent *= 100;
    yPercent *= 100;
    setCursorState({
      xPercent: xPercent.toFixed(0),
      yPercent: yPercent.toFixed(0)
    });
  });


  return (
    <Theme style={{ background: `radial-gradient(circle at ${cursorState.xPercent}% ${cursorState.yPercent}%, #0a0f39aa 0%, #00000094 80%)` }} id="theme_element" scaling="90%" grayColor="mauve" accentColor="indigo" panelBackground="translucent" appearance="dark">
      <ThemePanel />
      <Container size="4">
        <Flex gap="4" direction="row">
          <Section width="50%">
            <Flex gap="4" direction="column">
              <Heading mt="6" size="9">Ted Fawke</Heading>
              <Heading weight="medium" size="6">Full Stack Web Developer</Heading>
              <Heading className="my_promise" weight="light" size="4" style={{color: "rgba(255, 255, 255, 0.73)"}}>I create custom, scalable software to help companies thrive on the web.</Heading>
            </Flex>
            <Navigation />
          </Section>
          <Section width="50%">
            <Flex gap="4" direction="column">
              <About />
            </Flex>
          </Section>
        </Flex>
      </Container>
    </Theme>
  );
}

export default App;
